//! Plugin Registry - 500+ curated plugins for DevUtils

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum PluginCategory {
    VersionControl,
    Cloud,
    Containers,
    InfrastructureAsCode,
    CICD,
    Languages,
    Frameworks,
    Databases,
    Observability,
    Security,
    AI,
    PackageRegistries,
    DevTools,
    HTTP,
    DataETL,
    SystemUtils,
    Networking,
    Mobile,
    Testing,
    Documentation,
    Notifications,
    Enterprise,
    Terminal,
}

impl PluginCategory {
    pub fn as_str(&self) -> &'static str {
        match self {
            PluginCategory::VersionControl => "Version Control",
            PluginCategory::Cloud => "Cloud",
            PluginCategory::Containers => "Containers",
            PluginCategory::InfrastructureAsCode => "Infrastructure as Code",
            PluginCategory::CICD => "CI/CD",
            PluginCategory::Languages => "Languages",
            PluginCategory::Frameworks => "Frameworks",
            PluginCategory::Databases => "Databases",
            PluginCategory::Observability => "Observability",
            PluginCategory::Security => "Security",
            PluginCategory::AI => "AI",
            PluginCategory::PackageRegistries => "Package Registries",
            PluginCategory::DevTools => "Dev Tools",
            PluginCategory::HTTP => "HTTP",
            PluginCategory::DataETL => "Data/ETL",
            PluginCategory::SystemUtils => "System Utils",
            PluginCategory::Networking => "Networking",
            PluginCategory::Mobile => "Mobile",
            PluginCategory::Testing => "Testing",
            PluginCategory::Documentation => "Documentation",
            PluginCategory::Notifications => "Notifications",
            PluginCategory::Enterprise => "Enterprise",
            PluginCategory::Terminal => "Terminal",
        }
    }

    pub fn all() -> Vec<PluginCategory> {
        vec![
            PluginCategory::VersionControl,
            PluginCategory::Cloud,
            PluginCategory::Containers,
            PluginCategory::InfrastructureAsCode,
            PluginCategory::CICD,
            PluginCategory::Languages,
            PluginCategory::Frameworks,
            PluginCategory::Databases,
            PluginCategory::Observability,
            PluginCategory::Security,
            PluginCategory::AI,
            PluginCategory::PackageRegistries,
            PluginCategory::DevTools,
            PluginCategory::HTTP,
            PluginCategory::DataETL,
            PluginCategory::SystemUtils,
            PluginCategory::Networking,
            PluginCategory::Mobile,
            PluginCategory::Testing,
            PluginCategory::Documentation,
            PluginCategory::Notifications,
            PluginCategory::Enterprise,
            PluginCategory::Terminal,
        ]
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegistryEntry {
    pub name: String,
    pub description: String,
    pub category: PluginCategory,
    pub tags: Vec<String>,
    pub author: &'static str,
    pub version: &'static str,
    pub downloads: u64,
    pub stars: u32,
    pub homepage: Option<&'static str>,
    pub featured: bool,
}

pub struct PluginRegistry {
    entries: HashMap<String, RegistryEntry>,
}

impl PluginRegistry {
    pub fn new() -> Self {
        let mut entries = HashMap::new();
        for plugin in all_plugins() {
            entries.insert(plugin.name.clone(), plugin);
        }
        Self { entries }
    }

    pub fn search(&self, query: &str) -> Vec<&RegistryEntry> {
        let q = query.to_lowercase();
        let mut results: Vec<&RegistryEntry> = self
            .entries
            .values()
            .filter(|e| {
                e.name.to_lowercase().contains(&q)
                    || e.description.to_lowercase().contains(&q)
                    || e.tags.iter().any(|t| t.to_lowercase().contains(&q))
                    || e.category.as_str().to_lowercase().contains(&q)
            })
            .collect();
        results.sort_by(|a, b| b.downloads.cmp(&a.downloads));
        results
    }

    pub fn by_category(&self, cat: &PluginCategory) -> Vec<&RegistryEntry> {
        let mut results: Vec<&RegistryEntry> = self
            .entries
            .values()
            .filter(|e| &e.category == cat)
            .collect();
        results.sort_by(|a, b| b.downloads.cmp(&a.downloads));
        results
    }

    pub fn featured(&self) -> Vec<&RegistryEntry> {
        let mut results: Vec<&RegistryEntry> =
            self.entries.values().filter(|e| e.featured).collect();
        results.sort_by(|a, b| b.downloads.cmp(&a.downloads));
        results
    }

    pub fn top(&self, n: usize) -> Vec<&RegistryEntry> {
        let mut all: Vec<&RegistryEntry> = self.entries.values().collect();
        all.sort_by(|a, b| b.downloads.cmp(&a.downloads));
        all.truncate(n);
        all
    }

    pub fn get(&self, name: &str) -> Option<&RegistryEntry> {
        self.entries.get(name)
    }

    pub fn count(&self) -> usize {
        self.entries.len()
    }

    pub fn categories_summary(&self) -> Vec<(String, usize)> {
        let mut map: HashMap<String, usize> = HashMap::new();
        for e in self.entries.values() {
            *map.entry(e.category.as_str().to_string()).or_insert(0) += 1;
        }
        let mut summary: Vec<(String, usize)> = map.into_iter().collect();
        summary.sort_by(|a, b| b.1.cmp(&a.1));
        summary
    }
}

impl Default for PluginRegistry {
    fn default() -> Self {
        Self::new()
    }
}

macro_rules! entry {
    ($name:expr, $desc:expr, $cat:expr, $tags:expr, $author:expr, $ver:expr, $dl:expr, $stars:expr, $hp:expr, $feat:expr) => {
        RegistryEntry {
            name: $name.to_string(),
            description: $desc.to_string(),
            category: $cat,
            tags: $tags.iter().map(|s: &&str| s.to_string()).collect(),
            author: $author,
            version: $ver,
            downloads: $dl,
            stars: $stars,
            homepage: $hp,
            featured: $feat,
        }
    };
}

